SELECT b.*, ste.site_nm AS site_nm, cd_bt.code_label AS bbm_type_cd_nm, cd_bct.code_label AS content_type_cd_nm, cd_bst.code_label AS scope_type_cd_nm FROM sy_bbm b LEFT JOIN sy_site ste ON ste.site_id = b.site_id LEFT JOIN sy_code cd_bt ON cd_bt.code_grp = 'BBM_TYPE' AND cd_bt.code_value = b.bbm_type_cd LEFT JOIN sy_code cd_bct ON cd_bct.code_grp = 'BBM_CONTENT_TYPE' AND cd_bct.code_value = b.content_type_cd LEFT JOIN sy_code cd_bst ON cd_bst.code_grp = 'BBM_SCOPE_TYPE' AND cd_bst.code_value = b.scope_type_cd
ORDER BY b.bbm_id ASC ORDER BY b.bbm_id DESC ORDER BY b.bbm_nm ASC ORDER BY b.bbm_nm DESC ORDER BY b.reg_date ASC ORDER BY b.reg_date DESC ORDER BY b.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

